import click
from click.core import Context

@click.command()
@click.pass_context
def inner(ctx):
    pass

@click.command()
@click.pass_context
def outer(ctx):
    # Simulate leak: invoke another command's context without closing it manually
    ctx.invoke(inner)

with Context(outer, validate_nesting=True) as ctx:
    ctx.invoke(inner)
    print('children after invoke (before close of sub):', ctx._children)
print('closed fine, root context validate_nesting=True works when properly nested')
