import click
from click.core import Context

@click.command()
def inner():
    pass

@click.command()
def outer():
    pass

ctx = Context(outer, validate_nesting=True)
sub_ctx = ctx._make_sub_context(inner)
try:
    ctx.close()
    print('ERROR: should have raised')
except RuntimeError as e:
    print('OK, raised:', e)
sub_ctx.close()
ctx.close()
print('closed after child closed - OK')
